Chaque README sera généré automatiquement à l'intérieur du dossier du département, en injectant les métadonnées suivantes :

✅ 1. SCRIPT generate_department_readmes.py
Crée ce fichier à la racine ou dans un dossier utilitaire :
pythonCopierModifier# :filename: generate_department_readmes.py
# :description: Génère un README.md pour chaque département à partir d’un template
# :type: utilitaire
# :services_used: aucun

import os

TEMPLATE_PATH = "/Users/nathalie/Dropbox/PROJETS/LANOSTRAI/_LNS3/resources/templates/department_readme_template.md"

DEPARTMENTS = {
    "Cortex_Centralis": {
        "name": "Cortex Centralis",
        "alias": "Direction Stratégique",
        "type": "transversal",
        "services": [
            "project_initializer",
            "arbitration_engine"
        ]
    },
    "Atrium_Motricis": {
        "name": "Atrium Motricis",
        "alias": "Département Exécutif",
        "type": "opérationnel",
        "services": [
            "send_pulse",
            "workflow_orchestrator"
        ]
    },
    "Bronchia_Externa": {
        "name": "Bronchia Externa",
        "alias": "Département Veille & Influence",
        "type": "sensoriel",
        "services": [
            "inspire_trend",
            "external_sensor"
        ]
    },
    "Enteron_Analytiqua": {
        "name": "Enteron Analytiqua",
        "alias": "Département Analyse",
        "type": "traitement",
        "services": [
            "digest_input",
            "extract_insight"
        ]
    },
    "Hepar_Regulatrix": {
        "name": "Hepar Regulatrix",
        "alias": "Département Régulation",
        "type": "équilibrage",
        "services": [
            "flow_balancer",
            "stress_detector"
        ]
    },
    "Manus_Creatoris": {
        "name": "Manus Creatoris",
        "alias": "Département Création",
        "type": "opérationnel",
        "services": [
            "generate_UI_component",
            "render_video"
        ]
    },
    "Uteris_Ideatica": {
        "name": "Uteris Ideatica",
        "alias": "Département Incubation",
        "type": "créatif",
        "services": [
            "incubate_idea",
            "prototype_builder"
        ]
    },
    "Immunis_Vigilans": {
        "name": "Immunis Vigilans",
        "alias": "Département Sécurité",
        "type": "défensif",
        "services": [
            "scan_vulnerabilities",
            "auto_test_runner"
        ]
    },
    "Sensoria_Qualitativa": {
        "name": "Sensoria Qualitativa",
        "alias": "Département Qualité UX/UI",
        "type": "évaluatif",
        "services": [
            "evaluate_visuals",
            "UX_flow_test"
        ]
    },
    "Symbiosis_BioMimetica": {
        "name": "Symbiosis BioMimetica",
        "alias": "Département Bio-Inspiration",
        "type": "recherche",
        "services": [
            "map_organ_to_function"
        ]
    },
    "Strata_Ecosophica": {
        "name": "Strata Ecosophica",
        "alias": "Département Écosophie",
        "type": "philosophique",
        "services": [
            "eco_filter",
            "natural_scenario"
        ]
    },
    "Core_Unconscious": {
        "name": "Core Unconscious",
        "alias": "Département Inconscient Symbolique",
        "type": "profond",
        "services": [
            "get_symbolic_pattern",
            "align_with_myth"
        ]
    },
    "Memoria_Reflexa": {
        "name": "Memoria Reflexa",
        "alias": "Département Réflexe & Suggestions",
        "type": "réactif",
        "services": [
            "auto_suggest_action"
        ]
    },
    "Tegumenta_Visualis": {
        "name": "Tegumenta Visualis",
        "alias": "Département Design",
        "type": "stylistique",
        "services": [
            "apply_brand_theme"
        ]
    },
    "Hippocampus_Documentis": {
        "name": "Hippocampus Documentis",
        "alias": "Département Documentation",
        "type": "archivage",
        "services": [
            "generate_guide",
            "log_project"
        ]
    },
    "Endocris_Regulantia": {
        "name": "Endocris Regulantia",
        "alias": "Département Croissance",
        "type": "hormonal",
        "services": [
            "release_growth_signal"
        ]
    },
}

def generate_readmes():
    with open(TEMPLATE_PATH, "r") as template_file:
        template = template_file.read()

    for dept, info in DEPARTMENTS.items():
        path = f"services/{dept}/README.md"
        content = template.format(
            name=info["name"],
            alias=info["alias"],
            type=info["type"],
            services="\n- " + "\n- ".join(info["services"])
        )
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w") as f:
            f.write(content)
        print(f"✅ README created: {path}")

if __name__ == "__main__":
    generate_readmes()


