# :scenario.py:
# :description: Classe Scenario permettant de chaîner l'exécution d'actions dans un ordre défini.
# :inputs: actions (liste de fonctions ou d'identifiants d'actions), contexte (dictionnaire optionnel)
# :outputs: résultats de chaque action, logs éventuels
# :file_type: class_definition

class Scenario:
    def __init__(self, name, actions=None, context=None):
        """
        Initialise un scénario avec un nom, une liste d'actions à exécuter, et un contexte partagé.

        :param name: Nom du scénario (str)
        :param actions: Liste des actions (fonctions ou identifiants de fonctions)
        :param context: Dictionnaire de données partagées entre les actions
        """
        self.name = name
        self.actions = actions or []
        self.context = context or {}
        self.results = []

    def add(self, action):
        """
        Ajoute une action à la fin du scénario.
        :param action: fonction ou identifiant d'action
        """
        self.actions.append(action)

    def run(self):
        """
        Exécute toutes les actions du scénario dans l'ordre, en passant le contexte si nécessaire.
        Stocke les résultats et retourne le contexte mis à jour.
        """
        print(f"[RUN] Scenario: {self.name}")
        for index, action in enumerate(self.actions):
            print(f" → Action {index+1}: {action.__name__ if callable(action) else action}")
            if callable(action):
                result = action(self.context)
            else:
                result = self.execute_named_action(action)
            self.results.append(result)
        return self.context

    def execute_named_action(self, action_name):
        """
        Exécute une action référencée par son nom (si ce n’est pas une fonction directe).
        À adapter selon ton système (BDD, registre, etc.)
        """
        raise NotImplementedError("Tu dois définir comment exécuter une action par nom")

    def __repr__(self):
        return f"<Scenario '{self.name}' with {len(self.actions)} actions>"

# :scenario_runner.py:
# :description: Classe ScenarioRunner utilisant SuperLoop pour exécuter proprement une suite d'actions (fonctions, prompts, actions nommées).
# :inputs: actions (list), context (dict)
# :outputs: contexte final enrichi, résultats, logs
# :file_type: class_definition

from superloop import SuperLoop
import builtins

class ScenarioRunner:
    def __init__(self, name, actions=None, context=None):
        self.name = name
        self.actions = actions or []
        self.context = context or {}
        self.results = []

    def add(self, action):
        self.actions.append(action)

    def run(self):
        print(f"\n🚀 [SCENARIO: {self.name}] DÉMARRAGE")

        def process_action(action):
            print(f" ▶️  {self._action_label(action)}")
            result = self.execute(action)
            self.results.append(result)
            return result

        SuperLoop(self.actions).each(process_action)

        print(f"✅ [SCENARIO: {self.name}] TERMINÉ")
        return self.context

    def execute(self, action):
        if callable(action):
            return action(self.context)

        elif isinstance(action, dict) and action.get("type") == "prompt":
            return self.execute_prompt(action)

        elif isinstance(action, str):
            return self.execute_named_action(action)

        else:
            raise ValueError(f"Type d'action non reconnu : {action}")

    def execute_named_action(self, name):
        action_fn = getattr(builtins, name, None)
        if not action_fn or not callable(action_fn):
            raise Exception(f"Action nommée '{name}' non trouvée.")
        return action_fn(self.context)

    def execute_prompt(self, prompt_config):
        prompt_name = prompt_config.get("name")
        prompt_vars = prompt_config.get("vars", {})

        print(f" 🤖 Prompt: {prompt_name} avec variables {prompt_vars}")

        result = f"[Réponse générée par {prompt_name}]"
        self.context[prompt_name] = result
        return result

    def _action_label(self, action):
        if callable(action):
            return action.__name__
        if isinstance(action, dict) and action.get("type") == "prompt":
            return f"prompt:{action.get('name')}"
        return str(action)

def run(self):
    report(f"SCENARIO '{self.name}' démarré", "info")

    def process_action(action):
        label = self._action_label(action)
        try:
            report(f"Exécution de l'action : {label}", "info")
            result = self.execute(action)
            self.results.append(result)
            report(f"Action '{label}' exécutée avec succès", "success")
            return result
        except Exception as e:
            report(f"Erreur dans l'action '{label}' : {e}", "error")
            self.context["error"] = str(e)
            raise e  # ou stop le process si tu veux

    try:
        SuperLoop(self.actions).each(process_action)
        report(f"SCENARIO '{self.name}' terminé", "success")
    except Exception as e:
        report(f"SCENARIO '{self.name}' interrompu suite à une erreur", "error")

    return self.context

