🧠 Scenario.py
pythonCopierModifier"""
:name: Scenario
:description: Objet de haut niveau permettant de définir, construire et exécuter des scénarios enchaînant des actions.
:created_at: 2025-04-19
:created_by: laNostr’AI
:version: 1.0
:tags: scenario, orchestration, modularité
:examples:
    - s = Scenario("scan_and_register", actions=["analyze_file_metadata", "register_file_metadata"])
      s.run()
:infos:
    - Les actions peuvent être des fonctions ou des noms d’actions accessibles via builtins ou Superloader.
:file_type: class_definition
"""

from domains.base.Object import Object
from superloop import SuperLoop
import builtins

class Scenario(Object):
    def __init__(self, name, actions=None, context=None):
        super().__init__()
        self.name = name
        self.actions = actions or []
        self.context = context or {}
        self.results = []

    def add_action(self, action):
        """Ajoute une action à la fin du scénario."""
        self.actions.append(action)

    def insert_action(self, action, index):
        """Insère une action à un index spécifique."""
        self.actions.insert(index, action)

    def remove_action(self, action_name):
        """Retire une action par son nom ou sa fonction."""
        self.actions = [a for a in self.actions if self._action_label(a) != action_name]

    def list_actions(self):
        """Retourne la liste des noms d’actions."""
        return [self._action_label(a) for a in self.actions]

    def run(self):
        """Exécute toutes les actions dans l’ordre. Envoie le contexte à chaque étape."""
        print(f"\n🎯 SCÉNARIO : {self.name} DÉMARRÉ")

        def process(action):
            label = self._action_label(action)
            print(f" → Exécution de {label}")
            result = self._execute(action)
            self.results.append(result)
            return result

        SuperLoop(self.actions).each(process)
        print(f"✅ SCÉNARIO : {self.name} TERMINÉ")
        return self.context

    def _execute(self, action):
        """Exécute une action selon son type."""
        if callable(action):
            return action(self.context)
        elif isinstance(action, str):
            return self._execute_named_action(action)
        elif isinstance(action, dict) and action.get("type") == "prompt":
            return self._execute_prompt(action)
        raise Exception("Type d'action non supporté")

    def _execute_named_action(self, name):
        """Exécute une fonction enregistrée dans builtins."""
        fn = getattr(builtins, name, None)
        if callable(fn):
            return fn(self.context)
        raise Exception(f"Action '{name}' introuvable dans builtins.")

    def _execute_prompt(self, prompt_data):
        """Exécute un prompt IA (à compléter avec SuperPrompt plus tard)."""
        nom = prompt_data.get("name")
        variables = prompt_data.get("vars", {})
        print(f" 🤖 Prompt : {nom} avec {variables}")
        result = f"[Réponse simulée du prompt {nom}]"
        self.context[nom] = result
        return result

    def _action_label(self, action):
        if callable(action):
            return action.__name__
        if isinstance(action, str):
            return action
        if isinstance(action, dict):
            return f"{action.get('type')}:{action.get('name')}"
        return str(action)

    def export(self):
        """Retourne un dictionnaire sérialisable du scénario."""
        return {
            "name": self.name,
            "actions": self.actions,
            "context": self.context,
            "results": self.results
        }

    def reset(self):
        """Réinitialise les résultats et le contexte du scénario."""
        self.results = []
        self.context = {}



