@api_bp.route('/api/<objet>/<method>', methods=['GET', 'POST'])
def api_router(objet, method):
    try:
        if request.method == 'POST':
            params = request.get_json() or {}
        else:
            params = request.args.to_dict()

        module = get_module(objet)
        if not module:
            return jsonify({"success": False, "error": f"Module '{objet}' introuvable."}), 404

        target = getattr(module, method, None)
        if not target or not callable(target):
            return jsonify({"success": False, "error": f"Méthode '{method}' non trouvée dans '{objet}'."}), 404

        result = target(**params)
        return jsonify({"success": True, "result": result})

    except Exception as e:
        logging.exception("Erreur API")
        return jsonify({"success": False, "error": str(e)})


