def get_records(context):
    table = context.get("table")
    conditions = context.get("conditions", {})
    columns = context.get("columns")
    if not table:
        return {"error": "Missing 'table'"}
    records = query.bdd_get_records(table, conditions, columns)
    return {"records": records}


def update_record(context):
    table = context.get("table")
    update_data = context.get("update_data", {})
    conditions = context.get("conditions", {})
    if not table or not update_data:
        return {"error": "Missing 'table' or 'update_data'"}
    query.bdd_update_records(table, update_data, conditions)
    return {"result": "updated"}


def delete_record(context):
    table = context.get("table")
    conditions = context.get("conditions", {})
    if not table or not conditions:
        return {"error": "Missing 'table' or 'conditions'"}
    query.bdd_delete_record(table, conditions)
    return {"result": "deleted"}


def get_children(context):
    parent_id = context.get("parent_id")
    table = context.get("table")
    if not table or parent_id is None:
        return {"error": "Missing 'table' or 'parent_id'"}
    children = query.bdd_get_records(table, {"parent_id": parent_id})
    return {"children": children}


def get_siblings(context):
    parent_id = context.get("parent_id")
    exclude_id = context.get("exclude_id")
    table = context.get("table")
    if not table or parent_id is None:
        return {"error": "Missing 'table' or 'parent_id'"}
    conditions = {"parent_id": parent_id}
    siblings = query.bdd_get_records(table, conditions)
    if exclude_id:
        siblings = [s for s in siblings if s["id"] != exclude_id]
    return {"siblings": siblings}


def get_tags(context):
    object_id = context.get("object_id")
    table = context.get("table", "tags")
    if not object_id:
        return {"error": "Missing 'object_id'"}
    tags = query.bdd_get_records(table, {"object_id": object_id})
    return {"tags": tags}


