pythonCopierModifier# :name: Superquery
# :description: Fournit des méthodes avancées pour interroger et enrichir les objets à partir de la base de données.
# :inputs: critères de sélection ou identifiants d'objet
# :outputs: liste d'objets enrichis ou résultats bruts de requête
# :tags: query, object, database
# :file_type: class_definition

import importlib
from app.models.core.query import Query
from app.models.core.query import ObjectCriteria, QueryBuilder, QueryExecute
import time

class SuperQuery(Query):
    """
    SuperQuery hérite de Query et fournit des méthodes avancées pour récupérer et enrichir les objets.
    """

    def __init__(self):
        object_module = importlib.import_module("app.models.core.object")
        self._object_instance = object_module.Object()

    def __getattr__(self, name):
        """Permet à Query d’accéder dynamiquement aux méthodes de l’objet."""
        return getattr(self._object_instance, name)

    @staticmethod
    def execute(criterias, enrich=False):
        builder = QueryBuilder.build_query_from_criteria(criterias)
        query, params = builder.build_query()
        return QueryExecute.execute(query, params, as_dict=True, enrich=enrich)

    @staticmethod
    def get_datas_by_object_id(object_id):
        query = """
            SELECT dd.data_key, od.data_value, od.details, dd.description
            FROM objects_datas od 
            JOIN datas_definitions dd ON od.data_key_id = dd.id 
            WHERE od.object_id = ?
        """
        return QueryExecute.execute(query, [object_id])

    @staticmethod
    def get_metas_by_object_id(object_id):
        query = """
            SELECT md.meta_key, om.meta_value, md.description 
            FROM objects_metas om 
            JOIN metas_definitions md ON om.meta_key_id = md.id 
            WHERE om.object_id = ?
        """
        return QueryExecute.execute(query, [object_id])

    @staticmethod
    def get_tags_by_object_id(object_id):
        return SuperQuery.get_target_objects_by_relation("tagged_with", object_id)

    @staticmethod
    def get_relations_by_object_id(object_id, as_source=True, relation_name=None):
        if as_source:
            if relation_name:
                return SuperQuery.get_target_objects_by_relation(relation_name, object_id)
            else:
                query = """
                    SELECT r.name as relation_name, o.id, o.name, o.ident 
                    FROM objects_relations rel 
                    JOIN relations r ON rel.relation_id = r.id 
                    JOIN objects o ON rel.object_target_id = o.id 
                    WHERE rel.object_src_id = ?
                """
                return QueryExecute.execute(query, [object_id])
        else:
            if relation_name:
                return SuperQuery.get_src_objects_by_relation(relation_name, object_id)
            else:
                query = """
                    SELECT r.name as relation_name, o.id, o.name, o.ident 
                    FROM objects_relations rel 
                    JOIN relations r ON rel.relation_id = r.id 
                    JOIN objects o ON rel.object_src_id = o.id 
                    WHERE rel.object_target_id = ?
                """
                return QueryExecute.execute(query, [object_id])

    @staticmethod
    def enrich_objects_with_metadata(objects):
        """Enrichit une liste d’objets avec leurs datas, metas, tags et relations."""
        if isinstance(objects, dict):
            objects = [objects]
        if not objects:
            return []

        for obj in objects:
            obj_id = obj["id"]
            obj["metas"] = {
                meta["meta_key"]: meta["meta_value"]
                for meta in SuperQuery.get_metas_by_object_id(obj_id)
            }
            obj["datas"] = {
                data["data_key"]: data["data_value"]
                for data in SuperQuery.get_datas_by_object_id(obj_id)
            }
            obj["tags"] = SuperQuery.get_tags_by_object_id(obj_id)
            obj["relations"] = {
                "as_source": SuperQuery.get_relations_by_object_id(obj_id, as_source=True),
                "as_target": SuperQuery.get_relations_by_object_id(obj_id, as_source=False)
            }

        return objects

    @staticmethod
    def get_object_by_id(id, enrich=False):
        criteria = ObjectCriteria().add_column("id", "=", id)
        return SuperQuery.execute(criteria, enrich)

    @staticmethod
    def get_objects_by_ids(ids, enrich=False):
        if not ids:
            return []
        placeholders = ", ".join("?" for _ in ids)
        query = f"SELECT * FROM objects WHERE id IN ({placeholders})"
        return QueryExecute.execute(query, ids, as_dict=True, enrich=enrich)

    @staticmethod
    def get_objects_by_type(type_name, enrich=False):
        criteria = ObjectCriteria().set_type(type_name)
        return SuperQuery.execute(criteria, enrich)

    @staticmethod
    def get_object_by_ident(ident, enrich=False):
        criteria = ObjectCriteria().add_column("ident", "=", ident)
        return SuperQuery.execute(criteria, enrich)

    @staticmethod
    def get_objects_by_meta(key, value, enrich=False):
