pythonCopierModifier# :name: SuperQuery
# :description: Fournit un moteur de requêtes modulaire pour rechercher, enrichir et relier des objets dans l’écosystème.
# :inputs: critères (type, ident, meta, relation, etc.)
# :outputs: liste d’objets enrichis
# :tags: query, object, data, relation
# :file_type: class_definition

import sqlite3
import os

DB_PATH = os.getenv("DB_PATH") or "system.db"

class ObjectCriteria:
    def __init__(self):
        self.type = None
        self.columns = []
        self.metas = []
        self.relations = []

    def set_type(self, object_type):
        self.type = object_type
        return self

    def add_column(self, column, operator, value):
        self.columns.append((column, operator, value))
        return self

    def add_meta(self, key, operator, value):
        self.metas.append((key, operator, value))
        return self

    def add_relation(self, relation_name, object_id, direction="src"):
        self.relations.append((relation_name, object_id, direction))
        return self

class QueryBuilder:
    @staticmethod
    def build_query_from_criteria(criteria):
        query = "SELECT o.* FROM objects o"
        joins = []
        conditions = []
        params = []

        if criteria.metas:
            joins.append("JOIN objects_metas om ON om.object_id = o.id")
            joins.append("JOIN metas_definitions md ON om.meta_key_id = md.id")
            for i, (key, operator, value) in enumerate(criteria.metas):
                conditions.append(f"md.meta_key = ? AND om.meta_value {operator} ?")
                params.extend([key, value])

        if criteria.relations:
            for i, (name, obj_id, direction) in enumerate(criteria.relations):
                rel_alias = f"rel{i}"
                r_alias = f"r{i}"
                joins.append(f"JOIN objects_relations {rel_alias} ON {rel_alias}.object_{'src' if direction == 'target' else 'target'}_id = o.id")
                joins.append(f"JOIN relations {r_alias} ON {r_alias}.id = {rel_alias}.relation_id")
                if direction == "src":
                    conditions.append(f"{r_alias}.name = ? AND {rel_alias}.object_target_id = ?")
                else:
                    conditions.append(f"{r_alias}.name = ? AND {rel_alias}.object_src_id = ?")
                params.extend([name, obj_id])

        if criteria.type:
            conditions.append("o.type = ?")
            params.append(criteria.type)

        for (col, op, val) in criteria.columns:
            conditions.append(f"o.{col} {op} ?")
            params.append(val)

        if joins:
            query += " " + " ".join(joins)

        if conditions:
            query += " WHERE " + " AND ".join(conditions)

        return QueryBuilder(query, params)

    def __init__(self, query, params):
        self.query = query
        self.params = params

    def build_query(self):
        return self.query, self.params

class QueryExecute:
    @staticmethod
    def execute(query, params=None, as_dict=True, enrich=False):
        try:
            conn = sqlite3.connect(DB_PATH)
            conn.row_factory = sqlite3.Row if as_dict else None
            cur = conn.cursor()
            cur.execute(query, params or [])
            rows = cur.fetchall()
            results = [dict(row) for row in rows] if as_dict else rows
            conn.close()
            return results
        except Exception as e:
            print(f"[ERROR] QueryExecute : {e}")
            return []

class SuperQuery:
    def __init__(self):
        pass

    @staticmethod
    def execute(criterias, enrich=False):
        builder = QueryBuilder.build_query_from_criteria(criterias)
        query, params = builder.build_query()
        results = QueryExecute.execute(query, params, as_dict=True)
        return SuperQuery.enrich_objects(results) if enrich else results

    @staticmethod
    def enrich_objects(objects):
        if not objects:
            return []
        for obj in objects:
            obj_id = obj.get("id")
            obj["metas"] = SuperQuery.get_metas_by_object_id(obj_id)
            obj["datas"] = SuperQuery.get_datas_by_object_id(obj_id)
            obj["tags"] = SuperQuery.get_tags_by_object_id(obj_id)
            obj["relations"] = {
                "as_source": SuperQuery.get_relations_by_object_id(obj_id, True),
                "as_target": SuperQuery.get_relations_by_object_id(obj_id, False),
            }
        return objects

    @staticmethod
    def get_datas_by_object_id(object_id):
        q = """
            SELECT dd.data_key, od.data_value 
            FROM objects_datas od 
            JOIN datas_definitions dd ON od.data_key_id = dd.id 
            WHERE od.object_id = ?
        """
        return QueryExecute.execute(q, [object_id])

    @staticmethod
    def get_metas_by_object_id(object_id):
        q = """
            SELECT md.meta_key, om.meta_value 
            FROM objects_metas om 
            JOIN metas_definitions md ON om.meta_key_id = md.id 
            WHERE om.object_id = ?
        """
        return QueryExecute.execute(q, [object_id])

    @staticmethod
    def get_tags_by_object_id(object_id):
        return SuperQuery.get_target_objects_by_relation("tagged_with", object_id)

    @staticmethod
    def get_relations_by_object_id(object_id, as_source=True):
        field = "object_src_id" if as_source else "object_target_id"
        q = f"""
            SELECT r.name, o.id, o.name, o.ident
            FROM objects_relations rel
            JOIN relations r ON rel.relation_id = r.id
            JOIN objects o ON rel.{'object_target_id' if as_source else 'object_src_id'} = o.id
            WHERE rel.{field} = ?
        """
        return QueryExecute.execute(q, [object_id])

    @staticmethod
    def get_object_by_id(object_id, enrich=False):
        criteria = ObjectCriteria().add_column("id", "=", object_id)
        return SuperQuery.execute(criteria, enrich)

    @staticmethod
    def get_object_by_ident(ident, enrich=False):
        criteria = ObjectCriteria().add_column("ident", "=", ident)
        return SuperQuery.execute(criteria, enrich)

    @staticmethod
    def get_objects_by_type(type_name, enrich=False):
        criteria = ObjectCriteria().set_type(type_name)
        return SuperQuery.execute(criteria, enrich)

    @staticmethod
    def get_objects_by_meta(meta_key, meta_value, enrich=False):
        criteria = ObjectCriteria().add_meta(meta_key, "=", meta_value)
        return SuperQuery.execute(criteria, enrich)

    @staticmethod
    def get_src_objects_by_relation(relation, target_id, enrich=False):
        criteria = ObjectCriteria().add_relation(relation, target_id, "target")
        return SuperQuery.execute(criteria, enrich)

    @staticmethod
    def get_target_objects_by_relation(relation, src_id, enrich=False):
        criteria = ObjectCriteria().add_relation(relation, src_id, "src")
        return SuperQuery.execute(criteria, enrich)

    @staticmethod
    def get_objects_by_column(column, value, enrich=False):
        criteria = ObjectCriteria().add_column(column, "=", value)
        return SuperQuery.execute(criteria, enrich)


