import os, inspect
from datetime import datetime
from pathlib import Path
from config.config import Config

class Log:
    @staticmethod
    def get_log_path():
        return os.path.abspath(os.path.join("logs", "system.log"))

    @staticmethod
    def log(message: str, log_type: str = "INFO", recipient: str = None):
        """
        Enregistre un message dans le fichier de log.

        :param message: Message à enregistrer
        :param log_type: Niveau du log (INFO, WARNING, TODO, etc.)
        :param recipient: Bénéficiaire ou responsable (facultatif)
        """
        try:
            frame = inspect.stack()[1]
            filename = Path(frame.filename).name
            lineno = frame.lineno
            function = frame.function
        except Exception:
            filename, lineno, function = "unknown", 0, "unknown"

        timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        entry = f"[{timestamp}] [{log_type}] ({filename}:{lineno} in {function}) {message}\n"

        log_file = Log.get_log_path()
        os.makedirs(os.path.dirname(log_file), exist_ok=True)

        with open(log_file, "a", encoding="utf-8") as f:
            f.write(entry)

        if Config.DEBUG:
            print(entry.strip())

        # Déclencheur automatique selon le type de log
        if log_type.upper() == "TODO":
            try:
                from services.Cortex_Centralis.project_initializer.actions.create_task import create_task
                create_task({"message": message, "recipient": recipient})
            except Exception as e:
                print(f"[Log Error] Erreur create_task: {e}")

        elif log_type.upper() == "WARNING":
            try:
                from services.Cortex_Centralis.project_initializer.actions.create_alert import create_alert
                create_alert({"message": message, "recipient": recipient})
            except Exception as e:
                print(f"[Log Error] Erreur create_alert: {e}")

    @staticmethod
    def log_message(message: str, type: str = "INFO", recipient: str = None):
        """Alias principal."""
        return Log.log(message, type, recipient)

    # Alias simplifiés
    @staticmethod
    def info(msg, recipient=None): return Log.log(msg, "INFO", recipient)
    @staticmethod
    def warning(msg, recipient=None): return Log.log(msg, "WARNING", recipient)
    @staticmethod
    def error(msg, recipient=None): return Log.log(msg, "ERROR", recipient)
    @staticmethod
    def todo(msg, recipient=None): return Log.log(msg, "TODO", recipient)
    @staticmethod
    def success(msg, recipient=None): return Log.log(msg, "SUCCESS", recipient)
    @staticmethod
    def system(msg, recipient=None): return Log.log(msg, "SYSTEM", recipient)

    # Retourne l’historique brut (optionnel)
    @staticmethod
    def get_logs(limit=100):
        path = Log.get_log_path()
        if not os.path.exists(path):
            return []
        with open(path, "r", encoding="utf-8") as f:
            lines = f.readlines()
        return lines[-limit:]


